#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
const int maxn=2e3+5,kd[][2]= {1,0,-1,0,0,1,0,-1};
int T,n,m,a[maxn][maxn],dis[maxn][maxn],lst[maxn*maxn][2],len,pre[maxn][maxn][2];
void print(int x,int y){
	if(x==1&&y==1) return;
	int pre_x=pre[x][y][0],pre_y=pre[x][y][1];
	print(pre_x,pre_y);
	if(x==pre_x-1) cout<<'U';
	if(x==pre_x+1) cout<<'D';
	if(y==pre_y-1) cout<<'L';
	if(y==pre_y+1) cout<<'R';
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>T;
	while(T--) {
		cin>>n>>m;
		fill(dis[0],dis[n+3],-1);
		for(int i=1; i<=n; i++) {
			for(int j=1; j<=m; j++) {
				char c;	cin>>c;
				a[i][j]= c=='1';
			}
		}
		lst[len][0]=lst[len=1][1]=1,dis[1][1]=0;
		lst[len=1][0]=1,lst[len][1]=1,dis[1][1]=0;
		for(int i=1; i<=len; i++) {
			int xx=lst[i][0],yy=lst[i][1];
			for(int j=0; j<4; j++) {
				int dx=xx+kd[j][0],dy=yy+kd[j][1];
				if(dx>=1&&dx<=n&&dy>=1&&dy<=m && a[xx][yy]!=a[dx][dy] && dis[dx][dy]==-1) {
					lst[++len][0]=dx,lst[len][1]=dy;
					dis[dx][dy]=dis[xx][yy]+1;
					pre[dx][dy][0]=xx,pre[dx][dy][1]=yy;
				}
			}
		}
		if(dis[n][m]==-1) cout<<-1<<endl;
		else {
			cout<<dis[n][m]<<endl;
			print(n,m);
			cout<<endl;
		}
	}
	return 0;
}
